
"use client";

import { useState, useEffect, useTransition } from 'react';
import { useSearchParams, useParams } from 'next/navigation';
import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle, Trash2, ArrowLeft, Loader2, Edit, Save, X, Settings, Star } from 'lucide-react';
import Link from 'next/link';
import Image from 'next/image';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { getMenusByVendorId, addMenuItem, deleteMenuItem, updateMenuItem, addMenuOption, deleteMenuOption, setMenuOptionDefault, type MenuItem, type MenuOptionGroup } from '@/ai/flows/menu-flow';
import { Label } from '@/components/ui/label';
import { Switch } from "@/components/ui/switch";
import { Badge } from '@/components/ui/badge';

type EditingState = {
  itemId: string;
  name: string;
  price: string;
  imageUrl: string;
};


export default function MenuAdminPage() {
  const { vendorId } = useParams() as { vendorId: string };
  const searchParams = useSearchParams();
  const vendorName = searchParams.get('name') || '店家';
  const { toast } = useToast();

  const [menu, setMenu] = useState<MenuItem[]>([]);
  const [newItemName, setNewItemName] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  const [newItemImageUrl, setNewItemImageUrl] = useState('');
  
  const [isLoading, setIsLoading] = useState(true);
  const [isPending, startTransition] = useTransition();
  const [editingState, setEditingState] = useState<EditingState | null>(null);
  
  const [selectedItem, setSelectedItem] = useState<MenuItem | null>(null);
  const [newOptionGroup, setNewOptionGroup] = useState('');
  const [newOptionChoice, setNewOptionChoice] = useState('');
  const [newOptionPrice, setNewOptionPrice] = useState('0');
  const [newOptionIsDefault, setNewOptionIsDefault] = useState(false);


  const fetchMenu = async () => {
    setIsLoading(true);
    try {
      const fetchedMenu = await getMenusByVendorId(vendorId);
      setMenu(fetchedMenu);
      // If an item was selected, update its data
      if (selectedItem) {
          const updatedSelectedItem = fetchedMenu.find(item => item.id === selectedItem.id);
          setSelectedItem(updatedSelectedItem || null);
      }
    } catch (error) {
      console.error("讀取菜單失敗:", error);
      toast({ variant: "destructive", title: "讀取菜單失敗", description: "無法從 Google Sheet 讀取菜單。" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchMenu();
  }, [vendorId]);

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemName.trim() || !newItemPrice.trim()) {
      toast({ variant: "destructive", title: "請輸入品項名稱和價格" });
      return;
    }
    
    const price = parseInt(newItemPrice, 10);
    if (isNaN(price) || price <= 0) {
      toast({ variant: "destructive", title: "請輸入有效的價格" });
      return;
    }
    
    startTransition(async () => {
      try {
        await addMenuItem({ vendorId, name: newItemName, price, imageUrl: newItemImageUrl });
        toast({ title: "品項已新增", description: `${newItemName} 已成功新增到菜單。` });
        setNewItemName('');
        setNewItemPrice('');
        setNewItemImageUrl('');
        await fetchMenu(); // Refresh list
      } catch (error) {
         toast({ variant: "destructive", title: "新增失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };
  
  const handleDeleteItem = (itemId: string, itemName: string) => {
    startTransition(async () => {
      try {
        await deleteMenuItem({ id: itemId });
        toast({ title: "品項已刪除", description: `${itemName} 已從菜單移除。`});
        await fetchMenu(); // Refresh list
      } catch (error) {
        toast({ variant: "destructive", title: "刪除失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };

  const handleEditClick = (item: MenuItem) => {
    setEditingState({
      itemId: item.id,
      name: item.name,
      price: item.price.toString(),
      imageUrl: item.imageUrl || '',
    });
  };

  const handleCancelEdit = () => {
    setEditingState(null);
  };

  const handleSaveEdit = () => {
    if (!editingState) return;
    
    const price = parseInt(editingState.price, 10);
    if (isNaN(price) || price <= 0) {
      toast({ variant: "destructive", title: "請輸入有效的價格" });
      return;
    }

    startTransition(async () => {
      try {
        await updateMenuItem({ 
          id: editingState.itemId, 
          name: editingState.name, 
          price: price, 
          imageUrl: editingState.imageUrl 
        });
        toast({ title: "品項已更新" });
        setEditingState(null);
        await fetchMenu();
      } catch (error) {
        toast({ variant: "destructive", title: "更新失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  }

  const handleAddOption = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedItem || !newOptionGroup.trim() || !newOptionChoice.trim()) {
      toast({ variant: "destructive", title: "請輸入選項群組和選項名稱" });
      return;
    }
    const priceDelta = parseInt(newOptionPrice, 10);
    if (isNaN(priceDelta)) {
      toast({ variant: "destructive", title: "請輸入有效的價格" });
      return;
    }
    
    startTransition(async () => {
      try {
        await addMenuOption({
          menuItemId: selectedItem.id,
          groupName: newOptionGroup,
          choiceName: newOptionChoice,
          priceDelta,
          isDefault: newOptionIsDefault,
        });
        toast({ title: "選項已新增" });
        setNewOptionChoice('');
        setNewOptionPrice('0');
        setNewOptionIsDefault(false);
        // Keep group name for convenience
        await fetchMenu();
      } catch (error) {
        toast({ variant: "destructive", title: "新增選項失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };

  const handleDeleteOption = (optionId: string) => {
    startTransition(async () => {
      try {
        await deleteMenuOption({ optionId });
        toast({ title: "選項已刪除" });
        await fetchMenu();
      } catch (error) {
        toast({ variant: "destructive", title: "刪除選項失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };

  const handleSetDefault = (optionId: string, menuItemId: string, groupName: string) => {
    startTransition(async () => {
      try {
        await setMenuOptionDefault({ optionId, menuItemId, groupName });
        toast({ title: "預設選項已更新" });
        await fetchMenu();
      } catch (error) {
        toast({ variant: "destructive", title: "設定預設失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  }

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="mb-6">
            <Link href="/admin" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground">
                <ArrowLeft className="h-4 w-4" />
                返回店家列表
            </Link>
        </div>
        <h1 className="font-headline text-3xl font-bold mb-2">編輯菜單：{decodeURIComponent(vendorName)}</h1>
        <p className="text-muted-foreground mb-6">管理 {decodeURIComponent(vendorName)} 的菜單品項。</p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {/* Add New Item */}
          <section className="lg:col-span-1">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <PlusCircle className="h-6 w-6" />
                  <span>新增菜單品項</span>
                </CardTitle>
                <CardDescription>為 {decodeURIComponent(vendorName)} 加入新的餐點。</CardDescription>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleAddItem} className="space-y-4">
                  <Input 
                    placeholder="品項名稱 (例如: 雞腿飯)" 
                    value={newItemName}
                    onChange={(e) => setNewItemName(e.target.value)}
                    disabled={isPending}
                  />
                  <Input 
                    type="number"
                    placeholder="價格" 
                    value={newItemPrice}
                    onChange={(e) => setNewItemPrice(e.target.value)}
                    disabled={isPending}
                  />
                  <Input 
                    placeholder="圖片網址 (選填)" 
                    value={newItemImageUrl}
                    onChange={(e) => setNewItemImageUrl(e.target.value)}
                    disabled={isPending}
                  />
                  <Button type="submit" className="w-full" disabled={isPending}>
                    {isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> 新增中...</> : '新增品項'}
                  </Button>
                </form>
              </CardContent>
            </Card>
          </section>
          
          {/* Menu Item List */}
          <section className="lg:col-span-2">
            <Card>
              <CardHeader>
                <CardTitle>現有品項</CardTitle>
                <CardDescription>點擊品項右側的 <Settings className="inline h-4 w-4" /> 來管理客製化選項。</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {isLoading ? (
                  <div className="flex justify-center items-center py-4">
                    <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                    <p className="ml-2 text-muted-foreground">讀取中...</p>
                  </div>
                ) : menu.length > 0 ? (
                  menu.map(item => (
                    <Card key={item.id} className="p-3 flex justify-between items-center transition-all duration-200"
                      style={{
                        boxShadow: selectedItem?.id === item.id ? '0 0 0 2px hsl(var(--ring))' : 'none'
                      }}
                    >
                      {editingState?.itemId === item.id ? (
                        // Editing View
                        <div className="flex-grow space-y-2">
                            <Input value={editingState.name} onChange={e => setEditingState({...editingState, name: e.target.value})} placeholder="品項名稱" disabled={isPending} />
                            <Input type="number" value={editingState.price} onChange={e => setEditingState({...editingState, price: e.target.value})} placeholder="價格" disabled={isPending} />
                            <Input value={editingState.imageUrl} onChange={e => setEditingState({...editingState, imageUrl: e.target.value})} placeholder="圖片網址" disabled={isPending} />
                        </div>
                      ) : (
                        // Default View
                        <div className="flex items-center gap-4">
                          <Image src="https://meee.com.tw/o6jiFMi" alt={item.name} width={64} height={64} className="rounded-md object-cover h-16 w-16" data-ai-hint="bento box" />
                          <div>
                              <p className="font-semibold">{item.name}</p>
                              <p className="text-sm text-muted-foreground">${item.price}</p>
                          </div>
                        </div>
                      )}
                      
                      <div className="flex items-center gap-1">
                        {editingState?.itemId === item.id ? (
                           <>
                            <Button variant="ghost" size="icon" onClick={handleSaveEdit} disabled={isPending} aria-label="儲存"> <Save className="h-4 w-4 text-primary" /> </Button>
                            <Button variant="ghost" size="icon" onClick={handleCancelEdit} disabled={isPending} aria-label="取消"> <X className="h-4 w-4" /> </Button>
                           </>
                        ) : (
                          <>
                            <Button variant="ghost" size="icon" onClick={() => handleEditClick(item)} disabled={isPending} aria-label="編輯"><Edit className="h-4 w-4" /></Button>
                            <Button variant="ghost" size="icon" onClick={() => setSelectedItem(item)} aria-label="管理選項" disabled={isPending}> <Settings className="h-4 w-4" /> </Button>
                            <AlertDialog>
                                <AlertDialogTrigger asChild>
                                    <Button variant="ghost" size="icon" aria-label={`刪除 ${item.name}`} disabled={isPending}>
                                        <Trash2 className="h-4 w-4 text-destructive" />
                                    </Button>
                                </AlertDialogTrigger>
                                <AlertDialogContent>
                                    <AlertDialogHeader><AlertDialogTitle>確定要刪除品項嗎？</AlertDialogTitle><AlertDialogDescription>此動作會將品項標示為非啟用，但不會真的從資料庫刪除。</AlertDialogDescription></AlertDialogHeader>
                                    <AlertDialogFooter><AlertDialogCancel>取消</AlertDialogCancel><AlertDialogAction onClick={() => handleDeleteItem(item.id, item.name)} disabled={isPending}>確定刪除</AlertDialogAction></AlertDialogFooter>
                                </AlertDialogContent>
                            </AlertDialog>
                          </>
                        )}
                      </div>
                    </Card>
                  ))
                ) : (
                  <p className="text-sm text-center text-muted-foreground py-4">這個店家還沒有任何菜單品項。</p>
                )}
              </CardContent>
            </Card>
          </section>

          {/* Item Options Management */}
          {selectedItem && (
            <section className="md:col-span-2 lg:col-span-3">
              <Card>
                <CardHeader>
                  <div className="flex justify-between items-start">
                    <div>
                      <CardTitle>管理選項：{selectedItem.name}</CardTitle>
                      <CardDescription>為「{selectedItem.name}」新增或移除客製化選項。</CardDescription>
                    </div>
                    <Button variant="ghost" size="icon" onClick={() => setSelectedItem(null)}><X className="h-4 w-4" /></Button>
                  </div>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Existing Options */}
                  <div>
                    <h3 className="font-semibold mb-3">現有選項</h3>
                    <div className="space-y-4">
                      {selectedItem.options && selectedItem.options.length > 0 ? selectedItem.options.map(group => (
                        <div key={group.name} className="p-3 border rounded-md bg-muted/20">
                          <p className="font-medium">{group.name}</p>
                          <ul className="mt-2 space-y-1 text-sm">
                            {group.choices.map(choice => (
                              <li key={choice.id} className="flex justify-between items-center group">
                                <div className="flex items-center gap-2">
                                  {choice.isDefault ? (
                                    <Badge variant="default" className="text-xs">預設</Badge>
                                  ) : (
                                    <Button 
                                      variant="outline" 
                                      size="sm" 
                                      className="h-6 px-2 text-xs opacity-0 group-hover:opacity-100 transition-opacity"
                                      onClick={() => handleSetDefault(choice.id, selectedItem.id, group.name)}
                                      disabled={isPending}
                                    >
                                      設為預設
                                    </Button>
                                  )}
                                  <span>{choice.name} (+${choice.priceDelta})</span>
                                </div>
                                <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => handleDeleteOption(choice.id)} disabled={isPending}>
                                  <Trash2 className="h-3 w-3 text-destructive" />
                                </Button>
                              </li>
                            ))}
                          </ul>
                        </div>
                      )) : <p className="text-sm text-muted-foreground">尚未設定任何選項。</p>}
                    </div>
                  </div>
                  {/* Add New Option Form */}
                  <div>
                     <h3 className="font-semibold mb-3">新增選項</h3>
                     <form onSubmit={handleAddOption} className="space-y-4 p-3 border rounded-md">
                        <Input placeholder="選項群組 (例: 飯量、辣度)" value={newOptionGroup} onChange={e => setNewOptionGroup(e.target.value)} disabled={isPending} />
                        <Input placeholder="選項名稱 (例: 飯多、小辣)" value={newOptionChoice} onChange={e => setNewOptionChoice(e.target.value)} disabled={isPending} />
                        <Input type="number" placeholder="價格變化 (例: 10 或 0)" value={newOptionPrice} onChange={e => setNewOptionPrice(e.target.value)} disabled={isPending} />
                        <div className="flex items-center space-x-2">
                            <Switch id="is-default-switch" checked={newOptionIsDefault} onCheckedChange={setNewOptionIsDefault} disabled={isPending} />
                            <Label htmlFor="is-default-switch">將此選項設為群組預設值</Label>
                        </div>
                        <Button type="submit" className="w-full" disabled={isPending}>
                          {isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> 新增中...</> : '新增選項'}
                        </Button>
                     </form>
                  </div>
                </CardContent>
              </Card>
            </section>
          )}

        </div>
      </main>
    </div>
  );
}
